\[
J\left(\begin{array}{c}
d X_{1} \\
\ldots \\
d X_{n}
\end{array}\right)=-d X_{0}\left(\begin{array}{c}
\partial P_{1} / \partial X_{0} \\
\ldots \\
\partial P_{n} / \partial X_{0}
\end{array}\right)
\]

\[
\left\{\begin{array}{l}
P_{1}+\left(\partial P_{1} / \partial X_{1}\right) d X_{1}+\ldots+\left(\partial P_{1} / \partial X_{n}\right) d X_{n}=0 \\
\ldots \\
P_{n}+\left(\partial P_{n} / \partial X_{1}\right) d X_{1}+\ldots+\left(\partial P_{n} / \partial X_{n}\right) d X_{n}=0
\end{array} \Longleftrightarrow\left(\begin{array}{c}
d X_{1} \\
d X_{2} \\
\ldots \\
d X_{n}
\end{array}\right)=-J^{-1}\left(\begin{array}{c}
P_{1} \\
\ldots \\
P_{n}
\end{array}\right)\right.
\]
